{/* Tabs navigation */}
<div className="w-full overflow-x-auto scrollbar-none mb-8 sm:mb-10 max-w-4xl mx-auto">
  <div className="flex items-center gap-1 sm:gap-1.5 p-1 bg-gray-100/60 dark:bg-white/5 rounded-2xl border border-gray-200/50 dark:border-white/10 w-max min-w-full sm:min-w-0 sm:w-fit sm:mx-auto">
    {[
      { id: "learner", label: "ಕಲಿಯುವವರು", icon: <UserPlus className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-4.5 md:h-4.5" /> },
      { id: "teacher", label: "ಕಲಿಸುವ ಮಕ್ಕಳು", icon: <Users className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-4.5 md:h-4.5" /> },
      { id: "mentor", label: "ಮಾರ್ಗದರ್ಶಕರು", icon: <Award className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-4.5 md:h-4.5" /> },
      { id: "organizer", label: "ಸಂಘಟಕರು", icon: <Shield className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-4.5 md:h-4.5" /> },
      { id: "donor", label: "ದಾನಿಗಳು", icon: <IndianRupee className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-4.5 md:h-4.5" /> },
      { id: "mla", label: "ಜನಪ್ರತಿನಿಧಿ", icon: <FileBadge className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-4.5 md:h-4.5" /> },
    ].map((tab) => (
      <button
        key={tab.id}
        type="button"
        onClick={() => {
          setActiveTab(tab.id as RoleType);
          setError(null);
        }}
        className={`flex items-center justify-center gap-1 sm:gap-1.5 py-1.5 px-2.5 sm:py-2 sm:px-3.5 md:px-5 rounded-xl text-[10px] sm:text-xs md:text-sm font-extrabold transition-all whitespace-nowrap ${
          activeTab === tab.id
            ? "bg-[#ED1C24] text-white shadow-md active:scale-95"
            : "text-gray-600 hover:bg-gray-250/20 hover:text-[#ED1C24] dark:text-gray-400 dark:hover:text-white"
        }`}
      >
        <span className="notranslate flex-shrink-0 flex items-center justify-center" translate="no">
          {tab.icon}
        </span>
        <span>{tab.label}</span>
      </button>
    ))}
  </div>
</div>

